                vowelPositions.add(c);

                // Count frequency
                counts.put(c, counts.getOrDefault(c, 0) + 1);

                // Record first occurrence index (lower index means earlier)
                if (!firstOccurrence.containsKey(c)) {
                    firstOccurrence.put(c, i);
                }
            }
        }

        // 2. Prepare a list of unique vowels present, along with their sorting criteria
        List<Character> uniqueVowels = new ArrayList<>(counts.keySet());

        // 3. Sort the vowels based on the criteria:
        //    a) Frequency (non-increasing / descending)
        //    b) First appearance position (non-decreasing / ascending)
        uniqueVowels.sort(new Comparator<Character>() {
            @Override
            public int compare(Character c1, Character c2) {
                int freq1 = counts.get(c1);
                int freq2 = counts.get(c2);

                // Primary sort: Frequency (descending)
                if (freq1 != freq2) {
                    return Integer.compare(freq2, freq1); // Higher frequency comes first
                } else {
                    // Secondary sort: First appearance position (ascending)
                    int pos1 = firstOccurrence.get(c1);
                    int pos2 = firstOccurrence.get(c2);
                    return Integer.compare(pos1, pos2); // Earlier appearance comes first
                }
            }
