            if (vowels.indexOf(originalChar) != -1) {
                // This position was a vowel. Replace it with the next sorted vowel.
                // We need to insert the sorted characters according to their total count, 
                // not just one by one based on the unique sorted list.

                // Instead of trying to map back to positions directly, let's build the sorted vowel sequence first.
            } else {
                sb.append(originalChar);
            }
        }

        // Build the sequence of all vowels sorted according to criteria
        StringBuilder sortedVowelSequence = new StringBuilder();
        for (char vowel : uniqueVowels) {
            int count = counts.get(vowel);
            for (int i = 0; i < count; i++) {
                sortedVowelSequence.append(vowel);
            }
